7	// MigrateStats reports what Migrate did in a single pass.
8	type MigrateStats struct {
9		// EventsExternalized is the number of beads whose inline events were
10		// moved to the .ddx/attachments/<id>/events.jsonl sidecar.
11		EventsExternalized int
12		// Archived is the number of closed beads moved from the active
13		// collection to beads-archive.
14		Archived int
15	}
16	
17	// Changed reports whether Migrate mutated on-disk state in this pass.
18	func (m MigrateStats) Changed() bool {
19		return m.EventsExternalized > 0 || m.Archived > 0
20	}
21	
22	// Migrate splits the existing active beads collection into the modern
23	// layout: closed beads' inline events are externalized to the attachment
24	// store (per ADR-004), and eligible closed beads are moved to the
25	// beads-archive partner (per TD-027). It is idempotent — a second call
26	// with no further changes is a no-op.
27	//
28	// Migrate uses a permissive archival policy (MinAge=0, MinActiveCount=0)
29	// so it drains the historical backlog. Routine archival (after Close)
30	// continues to use DefaultArchivePolicy.
31	func (s *Store) Migrate() (MigrateStats, error) {
32		return s.ArchiveWithEvents(ArchivePolicy{
33			Statuses:       []string{StatusClosed},
34			MinAge:         0,
35			MinActiveCount: 0,
36			BatchSize:      0, // unlimited
37		})
38	}
39	
40	// ArchiveWithEvents externalizes inline events for every bead whose status
41	// matches policy.Statuses, then archives eligible beads under the same
42	// policy. This is the operator-facing path used by `ddx bead archive` and
43	// the internal path used by `ddx bead migrate`.
44	func (s *Store) ArchiveWithEvents(policy ArchivePolicy) (MigrateStats, error) {
45		var stats MigrateStats
46		if s.Collection != DefaultCollection {
47			return stats, fmt.Errorf("bead: archive only runs from the active %q collection (got %q)", DefaultCollection, s.Collection)
48		}
49	
50		// Step 1: externalize inline events on every eligible-status bead under
51		// the active store's lock. This shrinks the row size before we try to
52		// archive, so the archive partner inherits already-thin rows.
53		err := s.WithLock(func() error {
54			beads, _, rerr := s.readAllLatestRaw()
55			if rerr != nil {
56				return rerr
57			}
58			dirty := false
59			for i := range beads {
60				if !containsString(policy.Statuses, beads[i].Status) {
61					continue
62				}
63				if !hasInlineEvents(&beads[i]) {
64					continue
65				}
66				if eerr := s.externalizeEventsInPlace(&beads[i]); eerr != nil {
67					return eerr
68				}
69				stats.EventsExternalized++
70				dirty = true
71			}
72			if !dirty {
73				return nil
74			}
75			return s.WriteAll(beads)
76		})
77		if err != nil {
78			return stats, fmt.Errorf("bead: archive externalize: %w", err)
79		}
80	
81		moved, err := s.Archive(policy)
82		if err != nil {
83			return stats, fmt.Errorf("bead: archive: %w", err)
84		}
85		stats.Archived = len(moved)
86		return stats, nil
87	}
88	
89	// hasInlineEvents reports whether a bead carries any inline events that
90	// can still be externalized. An empty array counts as "no inline events"
91	// so a second migrate pass on an already-externalized bead is a no-op.
92	func hasInlineEvents(b *Bead) bool {
93		if b == nil || b.Extra == nil {
94			return false
95		}
96		raw, ok := b.Extra["events"]
97		if !ok {
98			return false
99		}
100		return len(decodeBeadEvents(raw)) > 0
101	}
